import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import {
  TagsInput as TagsInputPrimitive,
  useTagsInput,
  useTagsInputContext,
  useTagsInputItemContext,
} from '@ark-ui/react/tags-input';
import { clsx } from 'clsx';
import { Children, cloneElement, forwardRef } from 'react';
import { CloseIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './TagsInput.module.css';

const TagsInputRoot = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.Root>,
  ComponentProps<typeof TagsInputPrimitive.Root>
>(function TagsInputRoot({ asChild, children, className, ...props }, ref) {
  return (
    <TagsInputPrimitive.Root
      ref={ref}
      asChild={asChild}
      data-slot="tags-input-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </TagsInputPrimitive.Root>
  );
});

const TagsInputRootProvider = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.RootProvider>,
  ComponentProps<typeof TagsInputPrimitive.RootProvider>
>(function TagsInputRootProvider({ asChild, children, className, ...props }, ref) {
  return (
    <TagsInputPrimitive.RootProvider
      ref={ref}
      asChild={asChild}
      data-slot="tags-input-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </TagsInputPrimitive.RootProvider>
  );
});

const TagsInputLabel = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.Label>,
  ComponentProps<typeof TagsInputPrimitive.Label>
>(function TagsInputLabel({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.Label
      ref={ref}
      data-slot="tags-input-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputControl = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.Control>,
  ComponentProps<typeof TagsInputPrimitive.Control>
>(function TagsInputControl({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.Control
      ref={ref}
      data-slot="tags-input-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputItem = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.Item>,
  ComponentProps<typeof TagsInputPrimitive.Item>
>(function TagsInputItem({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.Item
      ref={ref}
      data-slot="tags-input-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputItemPreview = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.ItemPreview>,
  ComponentProps<typeof TagsInputPrimitive.ItemPreview>
>(function TagsInputItemPreview({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.ItemPreview
      ref={ref}
      data-slot="tags-input-item-preview"
      className={clsx(styles.itemPreview, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputItemText = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.ItemText>,
  ComponentProps<typeof TagsInputPrimitive.ItemText>
>(function TagsInputItemText({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.ItemText
      ref={ref}
      data-slot="tags-input-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputItemDeleteTrigger = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.ItemDeleteTrigger>,
  ComponentProps<typeof TagsInputPrimitive.ItemDeleteTrigger>
>(function TagsInputItemDeleteTrigger({ className, children, ...props }, ref) {
  return (
    <TagsInputPrimitive.ItemDeleteTrigger
      ref={ref}
      data-slot="tags-input-item-delete-trigger"
      className={clsx(styles.itemDeleteTrigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CloseIcon />}
    </TagsInputPrimitive.ItemDeleteTrigger>
  );
});

const TagsInputItemInput = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.ItemInput>,
  ComponentProps<typeof TagsInputPrimitive.ItemInput>
>(function TagsInputItemInput({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.ItemInput
      ref={ref}
      data-slot="tags-input-item-input"
      className={clsx(styles.itemInput, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputInput = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.Input>,
  ComponentProps<typeof TagsInputPrimitive.Input>
>(function TagsInputInput({ className, ...props }, ref) {
  return (
    <TagsInputPrimitive.Input
      ref={ref}
      data-slot="tags-input-input"
      className={clsx(styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

const TagsInputClearTrigger = forwardRef<
  ComponentRef<typeof TagsInputPrimitive.ClearTrigger>,
  ComponentProps<typeof TagsInputPrimitive.ClearTrigger>
>(function TagsInputClearTrigger(
  {
    asChild,
    className,
    children,
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledBy,
    ...props
  },
  ref,
) {
  const triggerClassName = clsx(styles.clearTrigger, normalizeClassName(className));

  if (asChild || children != null) {
    return (
      <TagsInputPrimitive.ClearTrigger
        ref={ref}
        asChild={asChild}
        data-slot="tags-input-clear-trigger"
        className={triggerClassName}
        aria-label={ariaLabel}
        aria-labelledby={ariaLabelledBy}
        {...props}
      >
        {children}
      </TagsInputPrimitive.ClearTrigger>
    );
  }

  return (
    <TagsInputPrimitive.ClearTrigger
      ref={ref}
      asChild
      data-slot="tags-input-clear-trigger"
      className={triggerClassName}
      {...props}
    >
      <CloseButton.Root
        aria-label={ariaLabel ?? (ariaLabelledBy == null ? 'Clear tags' : undefined)}
        aria-labelledby={ariaLabelledBy}
      />
    </TagsInputPrimitive.ClearTrigger>
  );
});

function withHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = <TagsInputPrimitive.HiddenInput data-slot="tags-input-hidden-input" />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

const TagsInputContext = TagsInputPrimitive.Context;

function TagsInputItems() {
  return (
    <TagsInputContext>
      {(tagsInput) =>
        tagsInput.value.map((value, index) => (
          <TagsInputItem key={`${value}-${index}`} index={index} value={value}>
            <TagsInputItemPreview>
              <TagsInputItemText>{value}</TagsInputItemText>
              <TagsInputItemDeleteTrigger aria-label={`Remove ${value}`} />
            </TagsInputItemPreview>
            <TagsInputItemInput />
          </TagsInputItem>
        ))
      }
    </TagsInputContext>
  );
}

const TagsInput = Object.assign(TagsInputRoot, {
  Root: TagsInputRoot,
  RootProvider: TagsInputRootProvider,
  Label: TagsInputLabel,
  Control: TagsInputControl,
  Item: TagsInputItem,
  ItemContext: TagsInputPrimitive.ItemContext,
  ItemPreview: TagsInputItemPreview,
  ItemText: TagsInputItemText,
  ItemDeleteTrigger: TagsInputItemDeleteTrigger,
  ItemInput: TagsInputItemInput,
  Input: TagsInputInput,
  ClearTrigger: TagsInputClearTrigger,
  Context: TagsInputContext,
  Items: TagsInputItems,
});

export { TagsInput, useTagsInput, useTagsInputContext, useTagsInputItemContext };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    gap: var(--tags-input-gap, var(--field-gap, var(--spacing-1)));
    width: var(--tags-input-width, 100%);
    max-width: var(--tags-input-max-width, 24rem);
    color: var(--tags-input-color, var(--input-color, var(--color-foreground)));

    &[data-disabled] {
      opacity: var(
        --tags-input-disabled-opacity,
        var(--field-disabled-opacity, var(--input-disabled-opacity, var(--opacity-disabled)))
      );
    }
  }

  .label {
    display: inline-flex;
    align-items: center;
    gap: var(--tags-input-label-gap, var(--field-label-gap, var(--spacing-1)));
    color: var(--tags-input-label-color, var(--field-label-color, var(--color-foreground)));
    font-size: var(--tags-input-label-font-size, var(--field-label-font-size, var(--text-sm)));
    font-weight: var(
      --tags-input-label-font-weight,
      var(--field-label-font-weight, var(--weight-medium))
    );
    line-height: var(
      --tags-input-label-line-height,
      var(--field-label-line-height, var(--line-height-text-sm))
    );

    &[data-disabled] {
      opacity: var(
        --tags-input-disabled-opacity,
        var(--field-disabled-opacity, var(--input-disabled-opacity, var(--opacity-disabled)))
      );
    }
  }

  .control {
    box-sizing: border-box;
    display: flex;
    min-height: var(--tags-input-min-height, var(--input-height, var(--size-lg)));
    flex-wrap: wrap;
    align-items: center;
    gap: var(--tags-input-control-gap, var(--spacing-1));
    width: 100%;
    border: var(--tags-input-border-width, var(--input-border-width, var(--border-width-sm)))
      var(--input-border-style, solid)
      var(--tags-input-border-color, var(--input-border-color, var(--color-border)));
    border-radius: var(--tags-input-radius, var(--input-radius, var(--radius-md)));
    padding: var(--tags-input-padding-y, 0.3125rem) var(--tags-input-padding-x, 0.5rem);
    background-color: var(--tags-input-bg, var(--input-bg, var(--color-background)));
    color: var(--tags-input-color, var(--input-color, var(--color-foreground)));
    outline: var(
        --tags-input-focus-ring-width,
        var(--input-focus-ring-width, var(--input-border-width, var(--border-width-sm)))
      )
      solid transparent;
    outline-offset: var(
      --tags-input-focus-ring-offset,
      var(
        --input-focus-ring-offset,
        calc(
          0px - var(--tags-input-border-width, var(--input-border-width, var(--border-width-sm)))
        )
      )
    );
    transition:
      border-color var(--tags-input-transition, var(--input-transition, var(--transition-default))),
      outline-color var(--tags-input-transition, var(--input-transition, var(--transition-default))),
      background-color
        var(--tags-input-transition, var(--input-transition, var(--transition-default))),
      opacity var(--tags-input-transition, var(--input-transition, var(--transition-default)));

    &[data-focus] {
      outline-color: var(
        --tags-input-focus-ring-color,
        var(--input-focus-ring-color, var(--color-ring))
      );
    }

    &[data-invalid] {
      border-color: var(
        --tags-input-invalid-border-color,
        var(--input-border-color-invalid, var(--color-destructive))
      );

      &[data-focus] {
        outline-color: var(
          --tags-input-invalid-focus-ring-color,
          var(--input-border-color-invalid, var(--color-destructive))
        );
      }
    }

    &[data-readonly] {
      background-color: var(
        --tags-input-readonly-bg,
        var(--input-readonly-bg, var(--tags-input-bg, var(--color-background)))
      );
      color: var(
        --tags-input-readonly-color,
        var(--input-readonly-color, var(--tags-input-color, var(--color-foreground)))
      );
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }

  .item {
    display: contents;
  }

  .itemPreview {
    box-sizing: border-box;
    display: inline-flex;
    min-width: 0;
    max-width: 100%;
    align-items: center;
    gap: var(--tags-input-item-gap, var(--spacing-1));
    min-height: var(--tags-input-item-height, 1.5rem);
    border: var(--tags-input-item-border-width, var(--border-width-sm)) solid
      var(--tags-input-item-border-color, transparent);
    border-radius: var(--tags-input-item-radius, var(--radius-full));
    padding-block: var(--tags-input-item-padding-y, 0.125rem);
    padding-inline: var(--tags-input-item-padding-x, 0.5rem);
    background-color: var(--tags-input-item-bg, var(--color-secondary));
    color: var(--tags-input-item-color, var(--color-secondary-foreground));
    font-size: var(--tags-input-item-font-size, var(--text-xs));
    font-weight: var(--tags-input-item-font-weight, var(--weight-medium));
    line-height: var(--tags-input-item-line-height, var(--line-height-text-xs));
    transition:
      border-color var(--tags-input-transition, var(--transition-default)),
      background-color var(--tags-input-transition, var(--transition-default)),
      color var(--tags-input-transition, var(--transition-default)),
      box-shadow var(--tags-input-transition, var(--transition-default));

    &[data-highlighted] {
      box-shadow: 0 0 0 var(--tags-input-item-highlight-ring-width, var(--border-width-sm))
        var(--tags-input-item-highlight-ring-color, var(--color-ring));
    }

    &[data-disabled] {
      opacity: var(--tags-input-disabled-opacity, var(--opacity-disabled));
    }
  }

  .itemText {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .input,
  .itemInput {
    box-sizing: border-box;
    flex: 1 1 var(--tags-input-input-min-width, 7rem);
    min-width: var(--tags-input-input-min-width, 7rem);
    height: var(--tags-input-input-height, 1.5rem);
    margin: 0;
    border: 0;
    padding: 0 var(--tags-input-input-padding-x, 0.25rem);
    background-color: transparent;
    color: inherit;
    font: inherit;
    font-size: var(--tags-input-input-font-size, var(--input-font-size, var(--text-sm)));
    line-height: var(
      --tags-input-input-line-height,
      var(--input-line-height, var(--line-height-text-sm))
    );
    outline: 0;

    &::placeholder {
      color: var(
        --tags-input-placeholder-color,
        var(--input-placeholder-color, var(--color-muted-foreground))
      );
    }

    &[data-readonly],
    &:read-only {
      cursor: default;
    }
  }

  .itemInput {
    flex: 0 1 var(--tags-input-item-input-width, 7rem);
  }

  .itemDeleteTrigger {
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    width: var(--tags-input-trigger-size, 1rem);
    height: var(--tags-input-trigger-size, 1rem);
    border: 0;
    border-radius: var(--tags-input-trigger-radius, var(--radius-full));
    padding: 0;
    background-color: var(--tags-input-trigger-bg, transparent);
    color: var(--tags-input-trigger-color, currentColor);
    cursor: pointer;
    outline: 0;
    transition:
      background-color var(--tags-input-transition, var(--transition-default)),
      color var(--tags-input-transition, var(--transition-default)),
      opacity var(--tags-input-transition, var(--transition-default)),
      box-shadow var(--tags-input-transition, var(--transition-default));

    & > svg {
      width: var(--tags-input-trigger-icon-size, 0.625rem);
      height: var(--tags-input-trigger-icon-size, 0.625rem);
      flex: none;
      pointer-events: none;
    }

    &:hover {
      background-color: var(
        --tags-input-trigger-bg-hover,
        color-mix(in oklab, currentColor 12%, transparent)
      );
    }

    &:focus-visible {
      box-shadow: 0 0 0 var(--tags-input-trigger-focus-ring-width, var(--border-width-sm))
        var(--tags-input-trigger-focus-ring-color, var(--color-ring));
    }

    &[data-disabled],
    &:disabled {
      cursor: default;
      opacity: var(--tags-input-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }
  }

  .clearTrigger {
    --close-button-size: var(--tags-input-clear-trigger-size, 1.5rem);
    --close-button-icon-size: var(--tags-input-clear-trigger-icon-size, 0.75rem);
    --close-button-radius: var(--tags-input-clear-trigger-radius, var(--radius-sm));
    --close-button-bg: var(--tags-input-clear-trigger-bg, transparent);
    --close-button-bg-hover: var(--tags-input-clear-trigger-bg-hover, var(--color-muted));
    --close-button-color: var(--tags-input-clear-trigger-color, var(--color-muted-foreground));
    --close-button-color-hover: var(
      --tags-input-clear-trigger-color-hover,
      var(--color-foreground)
    );
    --close-button-focus-ring-color: var(--tags-input-trigger-focus-ring-color, var(--color-ring));
    --close-button-focus-ring-width: var(
      --tags-input-trigger-focus-ring-width,
      var(--border-width-sm)
    );

    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    width: var(--tags-input-clear-trigger-size, 1.5rem);
    height: var(--tags-input-clear-trigger-size, 1.5rem);
    margin-inline-start: auto;
    border: 0;
    border-radius: var(--tags-input-clear-trigger-radius, var(--radius-sm));
    padding: 0;
    background-color: var(--tags-input-clear-trigger-bg, transparent);
    align-self: center;
    color: var(--tags-input-clear-trigger-color, var(--color-muted-foreground));
    cursor: pointer;
    outline: 0;
    transition:
      background-color var(--tags-input-transition, var(--transition-default)),
      color var(--tags-input-transition, var(--transition-default)),
      opacity var(--tags-input-transition, var(--transition-default)),
      outline-color var(--tags-input-transition, var(--transition-default));

    & > svg {
      width: var(--tags-input-clear-trigger-icon-size, 0.75rem);
      height: var(--tags-input-clear-trigger-icon-size, 0.75rem);
      flex: none;
      pointer-events: none;
    }

    &:hover {
      background-color: var(--tags-input-clear-trigger-bg-hover, var(--color-muted));
      color: var(--tags-input-clear-trigger-color-hover, var(--color-foreground));
    }

    &:focus-visible {
      outline: var(--tags-input-trigger-focus-ring-width, var(--border-width-sm)) solid
        var(--tags-input-trigger-focus-ring-color, var(--color-ring));
      outline-offset: var(--tags-input-trigger-focus-ring-offset, 2px);
    }

    &[data-disabled],
    &:disabled {
      cursor: default;
      opacity: var(--tags-input-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }

    &[data-readonly] {
      display: none;
    }
  }
}
